/**
 * HEIC → JPEG converter for Immich Quick Download
 *
 * Conversion pipeline (in order):
 *
 * 1. Chrome ImageDecoder API (Chrome 94+)
 *    Works if OS has HEVC codec: macOS (always), Windows with
 *    "HEVC Video Extensions from Device Manufacturer" (free, Microsoft Store)
 *    → Full original resolution, your configured JPG quality
 *
 * 2. Canvas/Image native decode
 *    Same codec requirement as above, different API path
 *    → Full original resolution, your configured JPG quality
 *
 * 3. Immich /thumbnail?size=fullsize
 *    Server-side full-resolution JPEG — NO codec needed, works everywhere.
 *    Requires one-time setup: Immich Admin → Settings → Image → Full Size → enable
 *    → Full original resolution, Immich quality setting
 *
 * 4. Last resort: /thumbnail?size=preview (1440px cap, warns user)
 */
(function (global) {
  "use strict";

  async function tryImageDecoder(arrayBuffer, quality) {
    if (typeof ImageDecoder === "undefined") throw new Error("ImageDecoder unavailable");
    if (!await ImageDecoder.isTypeSupported("image/heic")) throw new Error("HEIC not supported");

    const decoder = new ImageDecoder({
      data: new ReadableStream({
        start(c) { c.enqueue(new Uint8Array(arrayBuffer)); c.close(); }
      }),
      type: "image/heic",
    });
    const { image } = await decoder.decode();
    const canvas = new OffscreenCanvas(image.displayWidth, image.displayHeight);
    canvas.getContext("2d").drawImage(image, 0, 0);
    image.close();
    decoder.close();
    const blob = await canvas.convertToBlob({ type: "image/jpeg", quality: quality / 100 });
    if (!blob || blob.size < 2000) throw new Error("output empty");
    return blob;
  }

  function tryCanvasDecode(arrayBuffer, quality) {
    return new Promise((resolve, reject) => {
      const url = URL.createObjectURL(new Blob([arrayBuffer], { type: "image/heic" }));
      const img = new Image();
      img.onload = () => {
        if (!img.naturalWidth) { URL.revokeObjectURL(url); return reject(new Error("naturalWidth=0")); }
        const c = document.createElement("canvas");
        c.width = img.naturalWidth; c.height = img.naturalHeight;
        c.getContext("2d").drawImage(img, 0, 0);
        URL.revokeObjectURL(url);
        c.toBlob(b => b && b.size > 2000 ? resolve(b) : reject(new Error("blank")), "image/jpeg", quality / 100);
      };
      img.onerror = () => { URL.revokeObjectURL(url); reject(new Error("onerror")); };
      img.src = url;
    });
  }

  async function tryImmichFullsize({ base, assetId, apiKey }) {
    const res = await fetch(`${base}/api/assets/${assetId}/thumbnail?size=fullsize`,
      { headers: { "x-api-key": apiKey } });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    const blob = await res.blob();
    if (blob.size < 50000) throw new Error("too small — fullsize probably not enabled in Immich");
    return blob;
  }

  async function tryImmichPreview({ base, assetId, apiKey }) {
    const res = await fetch(`${base}/api/assets/${assetId}/thumbnail?size=preview`,
      { headers: { "x-api-key": apiKey } });
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    return res.blob();
  }

  /** Returns { blob, method: "native" | "fullsize" | "preview" } */
  global.convertHeic = async function (arrayBuffer, quality, fallbackCtx) {

    // 1. ImageDecoder API
    try {
      return { blob: await tryImageDecoder(arrayBuffer, quality), method: "native" };
    } catch (e) { console.log("[Immich DL] ImageDecoder:", e.message); }

    // 2. Canvas decode
    try {
      return { blob: await tryCanvasDecode(arrayBuffer, quality), method: "native" };
    } catch (e) { console.log("[Immich DL] Canvas:", e.message); }

    // 3. Immich fullsize (full res, server-side)
    if (fallbackCtx) {
      try {
        return { blob: await tryImmichFullsize(fallbackCtx), method: "fullsize" };
      } catch (e) { console.log("[Immich DL] Fullsize:", e.message); }
    }

    // 4. Immich preview (1440px — last resort)
    if (fallbackCtx) {
      console.warn("[Immich DL] Using 1440px preview — NOT full resolution");
      return { blob: await tryImmichPreview(fallbackCtx), method: "preview" };
    }

    throw new Error("HEIC conversion failed — no codec and no Immich fallback available");
  };

})(window);
